import{_ as t,o as s,c as i,ai as a}from"./chunks/framework.DsLHkhEs.js";const u=JSON.parse('{"title":"DCTS Feature List","description":"","frontmatter":{},"headers":[],"relativePath":"Feature List.md","filePath":"Feature List.md"}'),o={name:"Feature List.md"};function r(n,e,l,d,c,g){return s(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="dcts-feature-list" tabindex="-1">DCTS Feature List <a class="header-anchor" href="#dcts-feature-list" aria-label="Permalink to “DCTS Feature List”">​</a></h1><p>This document will provide a list of all features[^1] and may describe some as well. If you&#39;re curious about what has been implemented and which features may come <a href="https://github.com/users/hackthedev/projects/6/views/1?filterQuery=-changelog-status%3AAdded" target="_blank" rel="noreferrer">check out the official to-do list</a>.</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p></p><p>The list below is somewhat simplified and may not show all details or features.</p></div><hr><h2 id="features" tabindex="-1">Features <a class="header-anchor" href="#features" aria-label="Permalink to “Features”">​</a></h2><ul><li><strong>Text Chat:</strong> persistent messages per channel with a <strong>markdown editor</strong>, with optional per channel permissions</li><li><strong>Mentions</strong>: Its possible to @mention users, roles and channels.</li><li><strong>Auto-complete:</strong> Mentions and emojis use a nice auto-complete that you can navigate with the arrow keys and select by pressing tab.</li><li><strong>Auth:</strong> User Registrations &amp; Logins, Rate Limits and PoW (proof of concept)</li><li><strong>User Accounts:</strong> Custom Profile Pictures and Banners, Status and About Me section.</li><li><strong>Server Roles &amp; Permissions:</strong> Role System with advanced (allow, <em><strong>deny</strong></em>, inherit) permission system and custom colors.</li><li><strong>Server Home:</strong> Server page featuring a banner display, server about text and articles as well as DMs.</li><li><strong>Desktop Client:</strong> A dedicated <a href="https://github.com/hackthedev/dcts-client-shipping/releases" target="_blank" rel="noreferrer">desktop client</a> for full integrity and advanced features like signature verification, data encryption and more!</li><li><strong>E2EE DM System:</strong> Private DMs with system notifications and support ticket functionality and report feature supporting end-to-end encryption when using the desktop client.</li><li><strong>Decentralized Server list:</strong> DCTS has a seamless, built-in server list that works for both desktop and web client.</li><li><strong>Seamless auto-discovery:</strong> Both servers and clients are automatically taking care of server discovery in the background.</li><li><strong>Message Signing &amp; Verification:</strong> Messages sent in a server chat or DM can be signed and verified when using the desktop client.</li><li><strong>User &amp; Server badges:</strong> When using the desktop client its possible to see user account badges and server badges.</li><li><strong>Article System:</strong> Possibility to create, edit, delete and pin different posts to display on server home page and notify members.</li><li><strong>Multiple Groups:</strong> Possibility to create multiple groups that each have their own channel tree with custom permissions (= Staff area)</li><li><strong>Opus Voice Chat</strong>: Chat with others using a microphone and a custom bitrate.</li><li><strong>Screensharing:</strong> Share you screen in a voice channel with customizable resolution, FPS and Bitrate.</li><li><strong>Camera Sharing:</strong> You can share your camera as well in addition to screensharing.</li><li><strong>Report System:</strong><ul><li>Possibility to report server chat messages and DM messages.</li><li>Slide-in report dashboard to view and manage reports with build in moderation actions: Delete Report, Delete Reported Message, Ban/Kick/Mute Reporter / Reported User, View profile of Reported User / Reporter, View Message Edit History.</li></ul></li><li><strong>Ticket System:</strong><ul><li>In the server home page, its possible to create a support ticket that appears where the DMs are listed</li><li>For Staff, its possible to claim a ticket and chat with your username, with <code>[Support Team]</code> as prefix or anonymously as <code>Support Team</code>.</li><li>Both the user and staff member can delete the ticket.</li></ul></li><li><strong>Advanced Bans &amp; Mutes:</strong> Possibility to mute or ban a user permanently or temporarily with a custom duration.</li><li><strong>Template Engine:</strong><ul><li>Dynamically loads variables from the config file and displays them where needed, resulting in dynamic SEO meta tag generation</li><li>Also used to display specific info across the entire app and very handy.</li></ul></li><li><strong>Background tasks:</strong> Used to delete old data and clean up the database</li><li><strong>Upload system:</strong><ul><li>Possibility to set a custom upload file size limit for each server role. Example: a donator role could have a bigger file upload limit</li><li>Uploaded files are MIME checked as well as size checked and will convert filenames to a safer filename.</li><li><strong>Supports Cloudflare Image CDN</strong>[^2]</li></ul></li><li><strong>Media Cache:</strong> Database media cache that will speed up turning urls and similar into actual images and similar.</li><li><strong>Emojis:</strong> Upload and use custom emojis, rename emojis, Emoji autocomplete</li><li><strong>Invite-only system:</strong> You can make your server invite-only, making users require an invite code in order to join.</li><li><strong>Audit Log:</strong> Log important actions taking place in the server, like expired invite links being automatically removed and more!</li><li><strong>Mobile Support:</strong> UI will work for mobile too, tho limited as of right now[^3]</li><li><strong>Plugin System:</strong> Its possible to create plugins that hook directly into the server and client, removing the need of bots.</li><li><strong>IP Banning:</strong> Automatic IP blacklisting if rate limit is reached. On member bans the IP is also banned.</li><li><strong>Hashing &amp; Encoding:</strong> Passwords are hashed and messages being encoded.</li><li><strong>Slot Limit + reserved slots:</strong> Possible to limit concurrent slots and define and use reserved slots based on role permission.</li><li><strong>Advanced Anti-Spam:</strong> There is a fully dynamic anti spam system that will adjust itself based on the community&#39;s activity which also goes into great detail to avoid false positives.</li></ul><p>[^3]: The mobile version may not fully support all features [^2]: Requires an API key [^1]: Some features may not be listed as its hard to list everything retrospectively</p>',7)])])}const p=t(o,[["render",r]]);export{u as __pageData,p as default};
